scenarios_list = []
all_nodes = {}

for row in SCENARIOS_DATA:
    sid, title, desc, emoji, color, prefix, win_say, acts_raw = row
    acts = [(a[0], list(a[1])) for a in acts_raw]
    meta = {
        "id": sid, "title": title, "description": desc,
        "emoji": emoji, "color": color,
        "startNode": f"{prefix}_a1_bridge", "totalSteps": 8
    }
    scenarios_list.append(meta)
    all_nodes.update(make_nodes(sid, prefix, acts, win_say))

result = {"scenarios": scenarios_list, "nodes": all_nodes}
with open(OUT, "w", encoding="utf-8") as f:
    json.dump(result, f, ensure_ascii=False)

print(f"Written {len(scenarios_list)} scenarios, {len(all_nodes)} nodes to {OUT}")
